import { useState } from "react";

const initialBooks = [
  { id: 1, title: "Clean Code", author: "Robert C Martin", genre: "Programming", available: true, cover: "https://covers.openlibrary.org/b/id/9611996-L.jpg" },
  { id: 2, title: "Harry Potter", author: "J K Rowling", genre: "Fantasy", available: true, cover: "https://covers.openlibrary.org/b/id/7984916-L.jpg" },
  { id: 3, title: "The Hobbit", author: "J R R Tolkien", genre: "Fantasy", available: true, cover: "https://covers.openlibrary.org/b/id/6979861-L.jpg" },
  { id: 4, title: "1984", author: "George Orwell", genre: "Dystopian", available: true, cover: "https://covers.openlibrary.org/b/id/7222246-L.jpg" },
  { id: 5, title: "The Alchemist", author: "Paulo Coelho", genre: "Philosophy", available: true, cover: "https://covers.openlibrary.org/b/id/8128691-L.jpg" },
  { id: 6, title: "Rich Dad Poor Dad", author: "Robert Kiyosaki", genre: "Finance", available: true, cover: "https://covers.openlibrary.org/b/id/8231856-L.jpg" },
  { id: 7, title: "Atomic Habits", author: "James Clear", genre: "Self Help", available: true, cover: "https://covers.openlibrary.org/b/id/10586817-L.jpg" },
  { id: 8, title: "Deep Work", author: "Cal Newport", genre: "Productivity", available: true, cover: "https://covers.openlibrary.org/b/id/9251804-L.jpg" },
  { id: 9, title: "Ikigai", author: "Hector Garcia", genre: "Lifestyle", available: true, cover: "https://covers.openlibrary.org/b/id/9251625-L.jpg" },
  { id: 10, title: "Think and Grow Rich", author: "Napoleon Hill", genre: "Motivation", available: true, cover: "https://covers.openlibrary.org/b/id/8319251-L.jpg" },

  { id: 11, title: "The Psychology of Money", author: "Morgan Housel", genre: "Finance", available: true, cover: "https://covers.openlibrary.org/b/id/10520883-L.jpg" },
  { id: 12, title: "Wings of Fire", author: "A P J Abdul Kalam", genre: "Biography", available: true, cover: "https://covers.openlibrary.org/b/id/8231995-L.jpg" },
  { id: 13, title: "You Can Win", author: "Shiv Khera", genre: "Motivation", available: true, cover: "https://covers.openlibrary.org/b/id/8167876-L.jpg" },
  { id: 14, title: "Zero to One", author: "Peter Thiel", genre: "Business", available: true, cover: "https://covers.openlibrary.org/b/id/8225631-L.jpg" },
  { id: 15, title: "Sapiens", author: "Yuval Noah Harari", genre: "History", available: true, cover: "https://covers.openlibrary.org/b/id/8168691-L.jpg" },

  { id: 16, title: "The Power of Now", author: "Eckhart Tolle", genre: "Spiritual", available: true, cover: "https://covers.openlibrary.org/b/id/8279256-L.jpg" },
  { id: 17, title: "The Monk Who Sold His Ferrari", author: "Robin Sharma", genre: "Motivation", available: true, cover: "https://covers.openlibrary.org/b/id/8235283-L.jpg" },
  { id: 18, title: "Start With Why", author: "Simon Sinek", genre: "Leadership", available: true, cover: "https://covers.openlibrary.org/b/id/8235114-L.jpg" },
  { id: 19, title: "Digital Fortress", author: "Dan Brown", genre: "Thriller", available: true, cover: "https://covers.openlibrary.org/b/id/8119865-L.jpg" },
  { id: 20, title: "Inferno", author: "Dan Brown", genre: "Thriller", available: true, cover: "https://covers.openlibrary.org/b/id/8161872-L.jpg" }
];

function Books() {
  const [books, setBooks] = useState(initialBooks);
  const [search, setSearch] = useState("");
  const [borrowed, setBorrowed] = useState(0);

  const filteredBooks = books.filter(book =>
    book.title.toLowerCase().includes(search.toLowerCase()) ||
    book.author.toLowerCase().includes(search.toLowerCase())
  );

  const requestBook = (id) => {
    if (borrowed >= 2) {
      alert("Borrow limit reached!");
      return;
    }

    setBooks(
      books.map(book =>
        book.id === id ? { ...book, available: false } : book
      )
    );

    setBorrowed(borrowed + 1);
    alert("Book requested successfully!");
  };

  return (
    <div>
      <h2>Library Books</h2>
      <p>Borrowed: {borrowed}/2</p>

      <input
        placeholder="Search by title or author"
        onChange={(e) => setSearch(e.target.value)}
      />

      <br /><br />

      {filteredBooks.map(book => (
        <div key={book.id} style={{ border: "1px solid gray", padding: "10px", margin: "10px" }}>
          <img src={book.cover} width="80" /><br />
          <strong>{book.title}</strong>
          <p>{book.author}</p>
          <p>{book.genre}</p>
          <p>Status: {book.available ? "Available ✅" : "Not Available ❌"}</p>

          {book.available && (
            <button onClick={() => requestBook(book.id)}>Request Book</button>
          )}
        </div>
      ))}
    </div>
  );
}

export default Books;
